func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type tryResult struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	nextAssignIdx := dispatch.AssignsLen
	for shipIdx := range oris {
		bestTry := tryResult{ok: false}
		id := total_ship + shipIdx
		ori, des := oris[shipIdx], dess[shipIdx]

		for i := 0; i < nextAssignIdx; i++ {
			assign := &dispatch.Assigns[i]
			oldCost := assign.Cost
			if assign.AddShip(id, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				if newCost >= 0 && (!bestTry.ok || delta < bestTry.costDelta) {
					bestTry.assignIdx = i
					bestTry.costDelta = delta
					bestTry.ok = true
				}
				assign.RemoveShip(id)
				assign.GenRoute()
			}
		}

		if bestTry.ok {
			target := &dispatch.Assigns[bestTry.assignIdx]
			target.AddShip(id, ori, des)
			target.GenRoute()
		} else {
			if nextAssignIdx >= MAXASSIGNS {
				continue
			}
			newAssign := &dispatch.Assigns[nextAssignIdx]
			if newAssign.AddShip(id, ori, des) {
				newAssign.GenRoute()
				nextAssignIdx++
				dispatch.AssignsLen = nextAssignIdx
			}
